export const formatINR = (value) => {
  const amount = Number(value) || 0;
  return new Intl.NumberFormat('en-IN', {
    style: 'currency',
    currency: 'INR',
    maximumFractionDigits: 2,
  }).format(amount);
};

export const getProductImage = (item) => {
  if (item?.image_url) return item.image_url;
  // Deterministic image placeholder keyed by item title/id.
  const seed =
    item?.sku ||
    item?.id ||
    item?.product_id ||
    item?.name ||
    item?.product_name ||
    'product';
  return `https://picsum.photos/seed/${encodeURIComponent(seed)}/600/450.jpg`;
};
